"""Generate single-precision exp10 fixture data."""

import os
import json
import numpy as np
from scipy.special import exp10

# Get the file path:
FILE = os.path.realpath(__file__)
DIR = os.path.dirname(FILE)


def gen(x, name):
    """Generate fixture data and write to file.

    # Arguments

    * `x`: domain (float32 ndarray)
    * `name::str`: output filename
    """
    x = x.astype(np.float32)
    y = exp10(x).astype(np.float32)

    data = {
        "x": x.tolist(),
        "expected": y.tolist()
    }

    filepath = os.path.join(DIR, name)
    with open(filepath, "w", encoding="utf-8") as outfile:
        json.dump(data, outfile)


def main():
    """Generate fixture data."""
    # Medium negative values
    x = np.linspace(np.float32(-38.0), np.float32(-1.0), 2003, dtype=np.float32)
    gen(x, "medium_negative.json")

    # Medium positive values
    x = np.linspace(np.float32(1.0), np.float32(38.0), 2003, dtype=np.float32)
    gen(x, "medium_positive.json")

    # Small negative values
    x = np.linspace(np.float32(-1.0), np.float32(-2.0**-23), 1007, dtype=np.float32)
    gen(x, "small_negative.json")

    # Small positive values
    x = np.linspace(np.float32(2.0**-23), np.float32(1.0), 1007, dtype=np.float32)
    gen(x, "small_positive.json")

    # Tiny values
    x = np.linspace(np.float32(-2.0**-23), np.float32(2.0**-23), 1007, dtype=np.float32)
    gen(x, "tiny.json")


if __name__ == "__main__":
    main()
